interface.signature:
interface DrillProps {
  difficulty: 'easy' | 'medium' | 'hard';
  sessionId: number;
  onComplete: (result: DrillResult) => void;
  onSkip?: () => void;  // Optional, deferred to Epic 4
}

interface DrillResult {
  id?: number;              // Auto-increment (Dexie)
  sessionId: number;        // FK to sessions
  timestamp: string;        // ISO 8601
  module: 'number_line' | 'spatial_rotation' | 'math_operations';
  difficulty: 'easy' | 'medium' | 'hard';
  isCorrect: boolean;
  timeToAnswer: number;     // milliseconds
  accuracy: number;         // 0-100

  // Spatial Rotation fields (Story 3.2 extended schema)
  shapeType?: string;       // e.g., 'triangle', 'pentagon'
  rotationDegrees?: number; // 0, 45, 90, 180, 270
  isMirrored?: boolean;     // true if horizontal flip
}
